```class Solution {
public:
    int countKDifference(vector<int>& nums, int k) {
        int count = 0;
        unordered_map<int, int> freq;
        for (int num : nums) {
            freq[num]++;
        }
        for (int num : nums) {
            if (freq.count(num - k) > 0) {
                count += freq[num - k];
            }
            if (freq.count(num + k) > 0) {
                count += freq[num + k];
            }
        }
        return count / 2;
    }
};```
